#import "TopicTalkViewController.h"
#import "MessageSendView.h"
#import "MessageModel.h"
#import "ChatMessageCell.h"

@interface TopicTalkViewController () <UITableViewDelegate, UITableViewDataSource, UITextFieldDelegate, NSURLSessionDataDelegate>

@property(strong, nonatomic) MessageSendView *messageView;
@property(strong, nonatomic) UITableView *chatTableView;
@property(strong, nonatomic) NSMutableArray<MessageModel *> *messages;
@property (nonatomic, assign) BOOL isDeleting;
// 以下属性用于消息拼接实现流式显示效果
@property(strong, nonatomic) NSMutableString *accumulatedResponse;
@property(strong, nonatomic) NSMutableString *buffer;
@property(strong, nonatomic) NSString *nowString;
@property(strong, nonatomic) NSString *preString;
@property (nonatomic, strong) NSURLSessionDataTask *dataTask;
@property (nonatomic, strong) NSArray *context;

@end

@implementation TopicTalkViewController
#pragma mark - Initialization


- (instancetype)init {
    self = [super init];
    if (self) {
        self.view.backgroundColor = BACKGROUND_COLOR;
        // 设置modal出来的模式是占满全屏幕
        self.modalPresentationStyle = UIModalPresentationFullScreen;
        // 添加通知观察者
        [self addObservers];

    }
    return self;
}

- (instancetype)initWithAccount:(AccountModel *)account Data:(NSString *)options{
    self = [super init];
    if (self) {
        // 在初始化时进行赋值
        self.name = account.aiName;
        self.aiID = account.ID;
        self.headerView.titleLabel.text = account.aiName;
        self.headerView.editButton.hidden = YES;
        self.iconimage = [UIImage imageNamed:@"My_image"];
        self.options = options;
        self.view.backgroundColor = BACKGROUND_COLOR;
        // 设置modal出来的模式是占满全屏幕
        self.modalPresentationStyle = UIModalPresentationFullScreen;
        // 添加通知观察者
        [self addObservers];
    }
    return self;
}

- (void)addObservers {

    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(keyboardWillShow:) name:UIKeyboardWillShowNotification object:nil];
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(keyboardWillHide:) name:UIKeyboardWillHideNotification object:nil];
    // 添加通知观察者
    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(onSendMessageButtonTapped:) name:@"发送了一条消息" object:nil];
}

#pragma mark - loadView & viewDidLoad & viewDidAppear & dealloc

- (void)loadView { // 创建并设置视图控制器的 view 属性
    [super loadView];
    [self setUpUI];
}

- (void)viewDidLoad { // 在视图控制器的 view 属性已经被加载到内存后调用。此时视图层次结构已经创建完成，通常用于视图的额外配置和初始化。
    [super viewDidLoad];
    self.accumulatedResponse = [[NSMutableString alloc] init];
    self.buffer = [[NSMutableString alloc] init];
    self.isDeleting=NO;
    [self setupMessages]; // 初始化消息数组
    [self setupDelegates]; // 设置代理
    [self scrollToBottom]; // 滚动到最下方最新消息
}

- (void)viewDidAppear:(BOOL)animated { //会在视图控制器的视图已经完全显示并且用户可以看到时被调用
    [super viewDidAppear:animated];
    [_headerView showAppearAnimation];
    [self.chatTableView reloadData]; // 刷新表格视图以显示消息
}

- (void)viewDidDisappear:(BOOL)animated {
    [super viewDidDisappear:animated];
    // 删除操作时出现一些bug，目前只能通过这种方法修改
    // 检测最后一条消息是否已经显示出来了，如果已经显示出来了就保留，如果还是"思考中"则删除最后一条消息
    if((![self.messages.lastObject.text isEqual:@"思考中..."])&&self.messages.count>1&&(!self.messages.lastObject.done)&&(!self.isDeleting)){
        self.messages.lastObject.context = self.messages[self.messages.count-3].context;
        self.messages.lastObject.done = YES;
        self.messages[self.messages.count-2].done=YES;
        self.messages[self.messages.count-3].context=@"";
        [MessageModel saveMessagesForAccount:self.aiID]; // 保存消息
        self.messageView.inputMessageField.enabled = YES;
        self.messageView.sendButton.enabled = YES; // 按钮恢复可点击
        self.messageView.sendButton.alpha = 1.0; // 恢复透明度
    }
    // 删除时也需要检测是否有任务存在且未完成，有则取消任务
    if (self.dataTask) {
        [self.dataTask cancel];
        self.dataTask = nil;  // 释放任务
    }
}

- (void)dealloc { //当一个视图控制器的生命周期结束且没有其他地方再引用它时，dealloc 会被调用。
    // 移除观察者
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

#pragma mark - UI Setup

- (void)setUpUI {
    [self.view addSubview:self.headerView];
    [self.view addSubview:self.chatTableView];
    [self.view addSubview:self.messageView];

    // 设置headerView约束
    [_headerView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view).offset(ZOOM(10));
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.bottom.equalTo(self.view).offset(ZOOM(-724));
    }];

    // 设置chatTableView约束
    [_chatTableView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.headerView.mas_bottom);
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.bottom.equalTo(self.messageView.mas_top);
    }];

    // 设置messageView约束
    [_messageView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.left.equalTo(self.view);
        make.right.equalTo(self.view);
        make.bottom.equalTo(self.view);
        make.height.mas_equalTo(ZOOM(88));
        make.width.mas_equalTo(self.view.width);
    }];

}

//Message初始化
- (void)setupMessages {
    [self.chatTableView registerClass:[ChatMessageCell class] forCellReuseIdentifier:@"ChatMessageCell"]; // 注册消息单元格类
    self.messages = [MessageModel messagesForAccount:self.aiID];
    if (self.messages.count == 0) {
        [self.messages addObject:[[MessageModel alloc] initWithText:self.options time:[NSDate date] type:MessageTypeReceived accountId:self.aiID cellHeight:[self getStringWidthToCellHeight:self.options] context:@"[]" Done:YES]];
    }
    // 获取最后一个消息，判断接收ai消息时是否被中断，最后一次对话无法完成，所以在这里删除
    MessageModel *lastMessage = [self.messages lastObject];
    if (!lastMessage.done) {
        // 删除最后两个元素
        [self.messages removeLastObject];
        [self.messages removeLastObject];
    }
}

- (void)setupDelegates {
    self.chatTableView.delegate = self;
    self.chatTableView.dataSource = self; // 添加数据源
    self.messageView.inputMessageField.delegate = self;
}

#pragma mark - UITableViewDataSource

- (NSInteger)tableView:(UITableView *)tableView numberOfRowsInSection:(NSInteger)section {
    // 返回消息的数量
    return self.messages ? [self.messages count] : 0;
}

- (UITableViewCell *)tableView:(UITableView *)tableView cellForRowAtIndexPath:(NSIndexPath *)indexPath {
    ChatMessageCell *cell = [tableView dequeueReusableCellWithIdentifier:@"ChatMessageCell" forIndexPath:indexPath];
    // 根据索引路径配置单元格
    MessageModel *message = self.messages[indexPath.row];
    UIImage* sicon = [UIImage imageNamed:@"DeUseravatar"];

    [cell configureWithMessage:message iconSendImage:sicon iconReceiveImage:self.iconimage topicName:self.name options:self.options];

    //[cell layoutIfNeeded];
    return cell;
}

#pragma mark - UITableViewDelegate

- (CGFloat)tableView:(UITableView *)tableView heightForRowAtIndexPath:(NSIndexPath *)indexPath {
    MessageModel *message = self.messages[indexPath.row];
    return message.cellHeight > 0 ? message.cellHeight : 60.0;
}

- (void)tableView:(UITableView *)tableView didSelectRowAtIndexPath:(NSIndexPath *)indexPath {
    // 关闭键盘
    [self.messageView.inputMessageField resignFirstResponder];
}

